+import { $internal } from '../common';
+import type { Schema } from '../storage';
+import type { Trait, TraitRecord } from '../trait/types';
+
+export const $aspect = Symbol('aspect');
+
+export type AspectInput = Trait | Aspect;
+
+export type Aspect<T extends readonly Trait[] = readonly Trait[]> = {
+    readonly id: number;
+    readonly traits: T;
+    readonly schema: AspectSchema<T>;
+    readonly [$aspect]: true;
+};
+
+export type AspectRecord<T extends Aspect = Aspect> = UnionToIntersection<
+    TraitRecord<T['traits'][number]>
+>;
+
+type AspectSchema<T extends readonly Trait[]> = UnionToIntersection<T[number]['schema']>;
+type UnionToIntersection<T> = (T extends any ? (value: T) => void : never) extends (
+    value: infer R
+) => void
+    ? R
+    : never;
+
+let aspectId = 0;
+
+export function isAspect(value: unknown): value is Aspect {
+    return Boolean((value as Aspect | undefined)?.[$aspect]);
+}
+
+export function createAspect<T extends readonly [AspectInput, AspectInput, ...AspectInput[]]>(
+    ...inputs: T
+): Aspect<ExtractAspectTraits<T>> {
+    const traits: Trait[] = [];
+    const fields = new Set<string>();
+
+    for (const input of inputs) {
+        const inputTraits = isAspect(input) ? input.traits : [input];
+        for (const trait of inputTraits) {
+            if (trait[$internal].relation) {
+                throw new Error('Koota: Relations cannot be used as aspect constituents.');
+            }
+
+            for (const field of Object.keys(trait.schema)) {
+                if (fields.has(field)) {
+                    throw new Error(`Koota: Aspect constituents overlap on field "${field}".`);
+                }
+                fields.add(field);
+            }
+            traits.push(trait);
+        }
+    }
+
+    const schema = Object.assign({}, ...traits.map((trait) => trait.schema)) as Schema;
+    return Object.freeze({
+        [$aspect]: true as const,
+        id: aspectId++,
+        traits: Object.freeze(traits),
+        schema,
+    }) as Aspect<ExtractAspectTraits<T>>;
+}
+
+type ExtractAspectTraits<T extends readonly AspectInput[]> = T extends readonly [
+    infer First,
+    ...infer Rest,
+]
+    ? First extends Aspect<infer Traits>
+        ? Rest extends readonly AspectInput[]
+            ? [...Traits, ...ExtractAspectTraits<Rest>]
+            : Traits
+        : First extends Trait
+          ? Rest extends readonly AspectInput[]
+              ? [First, ...ExtractAspectTraits<Rest>]
+              : [First]
+          : []
+    : [];
