+/** Query result variant that keeps each aspect as one merged callback value. */
+function createAspectQueryResult(
+    world: World,
+    entities: Entity[],
+    query: QueryInstance,
+    params: QueryParameter[]
+): QueryResult<any> {
+    const values = (entity: Entity) => {
+        const state: any[] = [];
+        for (const param of params) {
+            if (isAspect(param)) {
+                state.push(getTrait(world, entity, param));
+            } else if (isModifier(param)) {
+                if (param.type === 'not') continue;
+                for (const trait of param.traits) {
+                    if (trait[$internal].type !== 'tag') state.push(getTrait(world, entity, trait));
+                }
+            } else if (!isRelationPair(param) && (param as Trait)[$internal].type !== 'tag') {
+                state.push(getTrait(world, entity, param as Trait));
+            }
+        }
+        return state;
+    };
+
+    const results = Object.assign(entities, {
+        readEach(callback: any) {
+            for (let i = 0; i < entities.length; i++) callback(values(entities[i]), entities[i], i);
+            return results;
+        },
+        updateEach(callback: any, options: QueryResultOptions = { changeDetection: 'auto' }) {
+            for (let i = 0; i < entities.length; i++) {
+                const entity = entities[i];
+                const state = values(entity);
+                callback(state, entity, i);
+                if (!world.has(entity)) continue;
+
+                let index = 0;
+                for (const param of params) {
+                    if (isAspect(param)) {
+                        const value = state[index++];
+                        if (value) {
+                            for (const trait of param.traits) {
+                                const fields = Object.keys(trait.schema);
+                                const part = Object.fromEntries(fields.map((field) => [field, value[field]]));
+                                setTrait(world, entity, trait, part, options.changeDetection !== 'never');
+                            }
+                        }
+                    } else if (isModifier(param)) {
+                        if (param.type === 'not') continue;
+                        for (const trait of param.traits) {
+                            if (trait[$internal].type !== 'tag') setTrait(world, entity, trait, state[index++], options.changeDetection !== 'never');
+                        }
+                    } else if (!isRelationPair(param) && (param as Trait)[$internal].type !== 'tag') {
+                        setTrait(world, entity, param as Trait, state[index++], options.changeDetection !== 'never');
+                    }
+                }
+            }
+            return results;
+        },
+        useStores(callback: any) {
+            callback([], entities);
+            return results;
+        },
+        select(...nextParams: QueryParameter[]) {
+            return createAspectQueryResult(world, entities, query, nextParams);
+        },
+        sort(callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)) {
+            Array.prototype.sort.call(entities, callback);
+            return results;
+        },
+    });
+    return results as QueryResult<any>;
+}
